// ==========================================================
// GENERATE LEAD REPORT (DAILY)
// Creates a structured JSON report for Slack summary message
// Compatible with any NocoDB-based lead sheet
// ==========================================================

(() => {
  const leads = $items('LEADS') || [];
  const unsubscribes = $items('UNSUBSCRIBES') || [];

  const totalLeads = leads.length;
  const totalUnsubscribed = unsubscribes.length;

  // --- Status breakdown ---
  const statusMap = {};
  const sourceMap = {};
  const interestMap = {
    hotLeads: 0,
    interested: 0,
    notInterested: 0,
  };

  leads.forEach(item => {
    const data = item.json;

    // Normalize status, interest, source
    const status = (data.status || data.STATUS || '').toLowerCase();
    const source = (data.source || data.SOURCE || 'Unknown').trim();
    const interest = (data.interest || data.INTEREST || '').toLowerCase();

    // Count status
    if (status) statusMap[status] = (statusMap[status] || 0) + 1;

    // Count source
    sourceMap[source] = (sourceMap[source] || 0) + 1;

    // Count interest
    if (interest.includes('fire')) interestMap.fireLeads++;
    else if (interest.includes('hot')) interestMap.hotLeads++;
    else if (interest.includes('interested')) interestMap.interested++;
    else if (interest.includes('not')) interestMap.notInterested++;
  });

  // --- Email health (mock ratios) ---
  const verified = totalLeads - Math.floor(totalLeads * 0.05); // assume 5% unverified
  const reachableRatio = ((verified / totalLeads) * 100).toFixed(1);
  const unreachableRatio = (100 - reachableRatio).toFixed(1);

  // --- New leads today (mock if no time field) ---
  const newLeads = leads.slice(-3).map(l => l.json.email || l.json.EMAIL || 'Unknown');

  // --- Top lists ---
  const hotList = interestMap.hotLeads ? `${interestMap.hotLeads} Hot Leads` : 'None yet';
  const unsubTopList = unsubscribes.slice(-3).map(u => u.json.email || u.json.EMAIL || 'Unknown').join('\n• ') || 'None today';

  // --- Report date ---
  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'short', day: 'numeric' });

  return [
    {
      json: {
        today,
        totalLeads,
        totalUnsubscribed,
        status: Object.keys(statusMap).join(', ') || 'No status data',
        retarget1: statusMap['recontacted'] || 0,
        retarget2: statusMap['follow-up'] || 0,
        hotLeads: interestMap.hotLeads,
        interested: interestMap.interested,
        notInterested: interestMap.notInterested,
        contactsWithVerification: verified,
        reachableRatio,
        unreachableRatio,
        unsubToday: unsubscribes.length ? unsubscribes.length : 0,
        sourceCount: sourceMap,
        topList: newLeads.length ? `• ${newLeads.join('\n• ')}` : 'No new leads today.',
        hotList,
        unsubTopList,
      },
    },
  ];
})();
